-- ==================== 社团招新 (211) 10篇 ====================
INSERT INTO content_article (id, category_id, title, sub_title, content, cover_image, author_id, author_name, view_count, like_count, comment_count, is_top, is_hot, status, publish_time, create_by, create_time, update_by, update_time, deleted) VALUES
('2016300001001000001', '211', '2026年春季社团招新正式启动', '百团大战等你来', '# 社团招新公告\n\n亲爱的同学们：\n\n2026年春季社团招新活动正式启动！本次招新涵盖学术科技、文化艺术、体育竞技、公益志愿等多个类别，共有50余个社团参与。\n\n## 招新时间\n\n- 报名时间：2026年5月15日-5月20日\n- 面试时间：2026年5月22日-5月25日\n- 结果公布：2026年5月27日\n\n## 报名方式\n\n请登录校园智通平台，进入"社团招新"模块进行线上报名。每位同学最多可报名3个社团。\n\n## 注意事项\n\n1. 请认真填写报名表，如实填写个人信息\n2. 面试时请携带学生证\n3. 如有疑问请联系社团联合会\n\n欢迎各位同学踊跃参加，找到属于自己的精彩！', NULL, '2016200001000000001', '张明华', 156, 0, 0, 0, 0, 1, '2026-05-14 09:30:00', '2016200001000000001', '2026-05-14 09:30:00', '', '2026-05-14 09:30:00', 0),

('2016300001001000002', '211', '摄影协会招新 | 用镜头记录美好校园', '期待热爱摄影的你', '# 摄影协会招新\n\n你是否热爱摄影？是否想用镜头记录校园的每一个精彩瞬间？\n\n摄影协会现面向全校招新！\n\n## 我们提供\n\n- 专业摄影器材借用（单反、无人机、稳定器等）\n- 定期外拍活动（每月至少2次）\n- 摄影技巧培训（邀请专业摄影师授课）\n- 作品展示平台（校园摄影展、公众号专栏）\n- 参加各类摄影比赛机会\n\n## 报名要求\n\n1. 热爱摄影，有热情\n2. 有一定摄影基础优先\n3. 自备摄影设备优先（手机也可）\n\n## 联系方式\n\n- QQ群：123456789\n- 负责人：张同学 13812345678\n\n期待你的加入，让我们一起用镜头定格青春！', NULL, '2016200001000000003', '王浩然', 89, 0, 0, 0, 0, 1, '2026-05-15 14:20:00', '2016200001000000003', '2026-05-15 14:20:00', '', '2026-05-15 14:20:00', 0),

('2016300001001000003', '211', '辩论队招新 | 思辨青春，论道天下', '锻炼口才，提升思维', '# 辩论队招新公告\n\n你想在辩论场上唇枪舌剑吗？你想提升自己的逻辑思维能力吗？\n\n校辩论队现面向全校招新！\n\n## 队伍简介\n\n我校辩论队成立于2010年，曾获得省级辩论赛冠军3次，亚军5次，是一支有着优良传统的队伍。\n\n## 我们的活动\n\n- 每周一次队内训练\n- 每月一次校际交流赛\n- 参加省级、国家级辩论赛事\n- 承办校园辩论赛\n\n## 招新要求\n\n1. 热爱辩论，有团队精神\n2. 普通话标准，表达流畅\n3. 有辩论经验者优先\n\n## 报名方式\n\n请将个人简历发送至邮箱：debate@university.edu.cn\n\n面试时间：5月18日 14:00 地点：教学楼B203', NULL, '2016200001000000005', '刘子轩', 134, 0, 0, 0, 0, 1, '2026-05-13 16:00:00', '2016200001000000005', '2026-05-13 16:00:00', '', '2026-05-13 16:00:00', 0),

('2016300001001000004', '211', '动漫社招新 | 二次元爱好者集结', '一起追逐动漫梦想', '# 动漫社招新啦！\n\n喜欢动漫的你，还在等什么？快来加入我们吧！\n\n## 社团介绍\n\n动漫社是我校最大的二次元文化社团，拥有社员200余人。我们致力于推广动漫文化，为二次元爱好者提供交流平台。\n\n## 活动内容\n\n- 动漫放映会：每周五晚播放热门动漫\n- Cosplay活动：定期组织Cosplay拍摄和表演\n- 漫展参与：组团参加各地漫展\n- 绘画交流：原创漫画、插画创作\n- 游戏交流：各类二次元游戏讨论\n\n## 招新对象\n\n所有热爱动漫文化的同学，无论你是资深宅还是萌新，都欢迎加入！\n\n报名截止：5月20日', NULL, '2016200001000000002', '李思雨', 267, 0, 0, 0, 1, 1, '2026-05-14 11:30:00', '2016200001000000002', '2026-05-14 11:30:00', '', '2026-05-14 11:30:00', 0),

('2016300001001000005', '211', '书法协会招新 | 墨香四溢，传承经典', '感受传统文化魅力', '# 书法协会招新\n\n汉字之美，在于书法。书法协会诚邀你的加入！\n\n## 协会简介\n\n书法协会成立于2005年，是我校传统文化类社团的代表。我们以"传承书法艺术，弘扬传统文化"为宗旨。\n\n## 活动安排\n\n- 每周三下午：书法练习（提供笔墨纸砚）\n- 每月一次：书法讲座（邀请书法名家）\n- 每学期：书法作品展\n- 传统节日：写春联、送祝福活动\n\n## 招新要求\n\n热爱书法，愿意学习，有无基础均可。\n\n## 报名方式\n\n现场报名：学生服务中心一楼展台\n线上报名：校园智通平台\n\n让我们一起在墨香中感受传统文化的魅力！', NULL, '2016200001000000007', '孙伟杰', 78, 0, 0, 0, 0, 1, '2026-05-15 09:00:00', '2016200001000000007', '2026-05-15 09:00:00', '', '2026-05-15 09:00:00', 0),

('2016300001001000006', '211', '机器人协会招新 | 科技创新，智造未来', '机器人爱好者的天堂', '# 机器人协会招新\n\n对机器人感兴趣？想亲手制作属于自己的机器人？\n\n机器人协会欢迎你！\n\n## 协会优势\n\n- 专业实验室：配备3D打印机、激光切割机等设备\n- 竞赛机会：参加RoboMaster、挑战杯等赛事\n- 项目实践：参与校企合作项目\n- 技术培训：定期举办技术讲座\n\n## 招新方向\n\n1. 机械组：机器人结构设计与制作\n2. 电控组：电路设计与嵌入式开发\n3. 算法组：视觉识别、路径规划\n4. 宣传组：视频制作、新媒体运营\n\n## 报名条件\n\n理工科专业优先，有相关经验者优先。\n\n报名链接：robot.university.edu.cn', NULL, '2016200001000000009', '吴俊杰', 189, 0, 0, 0, 0, 1, '2026-05-16 14:30:00', '2016200001000000009', '2026-05-16 14:30:00', '', '2026-05-16 14:30:00', 0),

('2016300001001000007', '211', '街舞社招新 | 舞动青春，释放激情', '用舞蹈表达自我', '# 街舞社招新公告\n\n热爱舞蹈的你，快来加入街舞社吧！\n\n## 舞种介绍\n\n- Hip-hop：最流行的街舞风格\n- Breaking：力量与技巧的结合\n- Jazz：优雅与动感并存\n- Popping：机械舞，控制力的极致\n- Locking：锁舞，充满活力\n\n## 社团活动\n\n- 每周训练：专业舞蹈教室，资深教练指导\n- 校园演出：迎新晚会、社团文化节\n- 比赛交流：参加各类街舞比赛\n- 舞蹈派对：定期举办街舞派对\n\n## 招新对象\n\n热爱舞蹈，有无基础均可。我们有完善的培训体系，从零开始教你跳舞！\n\n报名方式：扫描海报二维码加入招新群', NULL, '2016200001000000004', '陈晓婷', 312, 0, 0, 0, 1, 1, '2026-05-17 10:00:00', '2016200001000000004', '2026-05-17 10:00:00', '', '2026-05-17 10:00:00', 0),

('2016300001001000008', '211', '文学社招新 | 以笔为媒，书写青春', '文学爱好者的精神家园', '# 文学社招新\n\n如果你热爱文学，喜欢写作，文学社是你最好的选择。\n\n## 社团简介\n\n文学社是我校历史最悠久的社团之一，创办于1998年。我们有自己的社刊《青春》，每学期出版一期。\n\n## 活动内容\n\n- 写作沙龙：每周一次，分享创作心得\n- 作家讲座：邀请知名作家分享创作经验\n- 采风活动：每学期组织外出采风\n- 征文比赛：举办校园征文大赛\n- 作品发表：推荐优秀作品至报刊杂志\n\n## 招新要求\n\n热爱文学，有一定写作能力，愿意参与社团活动。\n\n## 投稿方式\n\n请附上一篇原创作品（诗歌、散文、小说均可），发送至literature@university.edu.cn', NULL, '2016200001000000006', '赵雅琪', 145, 0, 0, 0, 0, 1, '2026-05-18 15:20:00', '2016200001000000006', '2026-05-18 15:20:00', '', '2026-05-18 15:20:00', 0),

('2016300001001000009', '211', '电竞社招新 | 游戏竞技，热血青春', '电竞爱好者的聚集地', '# 电竞社招新啦！\n\n热爱游戏的你，想找到志同道合的伙伴吗？\n\n电竞社欢迎你的加入！\n\n## 游戏项目\n\n- 英雄联盟\n- 王者荣耀\n- CS2\n- 原神\n- 永劫无间\n- 更多游戏等你来...\n\n## 社团福利\n\n- 专属电竞训练室\n- 参加高校联赛机会\n- 与职业选手交流机会\n- 电竞周边福利\n\n## 招新要求\n\n热爱游戏，有团队精神，段位不限。\n\n## 战队选拔\n\n我们正在组建校队，参加全国高校联赛，欢迎高水平玩家报名！\n\n报名QQ群：987654321', NULL, '2016200001000000008', '周雨萱', 423, 0, 0, 0, 1, 1, '2026-05-19 11:00:00', '2016200001000000008', '2026-05-19 11:00:00', '', '2026-05-19 11:00:00', 0),

('2016300001001000010', '211', '志愿者协会招新 | 奉献爱心，传递温暖', '让公益成为习惯', '# 志愿者协会招新\n\n你想用自己的力量帮助他人吗？你想让大学生活更有意义吗？\n\n加入志愿者协会，让我们一起传递爱与温暖！\n\n## 服务项目\n\n1. 社区服务：关爱老人、义务支教\n2. 环保行动：植树造林、垃圾分类宣传\n3. 大型活动：校运会、迎新等志愿服务\n4. 公益项目：爱心义卖、募捐活动\n\n## 社团福利\n\n- 志愿服务时长认证\n- 优秀志愿者评选\n- 社会实践证明\n- 结识志同道合的朋友\n\n## 招新要求\n\n热心公益，有责任心，愿意付出时间和精力。\n\n报名方式：校园智通平台-社团招新模块\n\n让我们一起，用行动温暖这个世界！', NULL, '2016200001000000010', '郑欣怡', 198, 0, 0, 0, 0, 1, '2026-05-20 09:30:00', '2016200001000000010', '2026-05-20 09:30:00', '', '2026-05-20 09:30:00', 0),

-- ==================== 文艺演出 (212) 10篇 ====================
('2016300001002000001', '212', '校园歌手大赛决赛即将拉开帷幕', '青春之声，唱响校园', '# 校园歌手大赛决赛\n\n经过初赛、复赛的激烈角逐，2026年校园歌手大赛决赛即将举行！\n\n## 比赛信息\n\n- 时间：2026年5月18日 19:00\n- 地点：大学生活动中心\n- 入场：免费，凭学生证入场\n\n## 决赛选手\n\n共有12位选手晋级决赛，他们将用歌声诠释青春与梦想。选手们来自不同学院，风格各异，有流行、民谣、摇滚等多种曲风。\n\n## 评委阵容\n\n- 音乐学院王教授\n- 知名音乐制作人李老师\n- 往届冠军张同学\n\n## 奖项设置\n\n- 一等奖1名：奖金3000元+录音棚录制机会\n- 二等奖2名：奖金1500元\n- 三等奖3名：奖金800元\n- 最佳人气奖：精美礼品\n\n欢迎全校师生前来观看，为你支持的选手加油！', NULL, '2016200001000000005', '刘子轩', 234, 0, 0, 0, 1, 1, '2026-05-16 10:00:00', '2016200001000000005', '2026-05-16 10:00:00', '', '2026-05-16 10:00:00', 0),

('2016300001002000002', '212', '话剧《雷雨》校园公演圆满成功', '经典再现，震撼人心', '# 话剧《雷雨》公演回顾\n\n5月15日晚，校话剧社在大学生活动中心成功公演经典话剧《雷雨》，现场座无虚席，观众反响热烈。\n\n## 演出回顾\n\n本次演出历时2个半小时，演员们精湛的演技将曹禺先生笔下的人物演绎得淋漓尽致。周朴园的专制、繁漪的压抑、周萍的矛盾......每个角色都深入人心。\n\n## 幕后故事\n\n为了这次演出，话剧社全体成员准备了整整3个月。从剧本研读到角色揣摩，从舞台布景到灯光音效，每一个细节都力求完美。\n\n## 观众评价\n\n"太震撼了！没想到校园话剧能达到这种水平。"\n"演员们的表演让我完全沉浸在剧情中。"\n\n## 后续安排\n\n应广大师生要求，话剧社计划在6月初加演一场，敬请期待！', NULL, '2016200001000000003', '王浩然', 187, 0, 0, 0, 0, 1, '2026-05-16 09:00:00', '2016200001000000003', '2026-05-16 09:00:00', '', '2026-05-16 09:00:00', 0),

('2016300001002000003', '212', '民乐团专场音乐会即将举办', '丝竹管弦，国乐飘香', '# 民乐团专场音乐会\n\n校民乐团将于5月20日晚举办"国韵华章"专场音乐会。\n\n## 演出信息\n\n- 时间：2026年5月20日 19:30\n- 地点：音乐厅\n- 票价：免费\n\n## 曲目单\n\n1. 《春江花月夜》- 民乐合奏\n2. 《二泉映月》- 二胡独奏\n3. 《十面埋伏》- 琵琶独奏\n4. 《渔舟唱晚》- 古筝独奏\n5. 《花好月圆》- 民乐合奏\n6. 更多精彩曲目...\n\n## 乐团简介\n\n校民乐团成立于2008年，现有团员60余人，涵盖二胡、琵琶、古筝、笛子、扬琴等多种乐器。乐团曾多次在省级大学生艺术展演中获奖。\n\n欢迎喜爱民乐的师生前来欣赏！', NULL, '2016200001000000001', '张明华', 156, 0, 0, 0, 0, 1, '2026-05-17 14:00:00', '2016200001000000001', '2026-05-17 14:00:00', '', '2026-05-17 14:00:00', 0),

('2016300001002000004', '212', '校园舞蹈大赛报名开始', '舞出青春，跳出精彩', '# 校园舞蹈大赛\n\n一年一度的校园舞蹈大赛即将开始！\n\n## 比赛分组\n\n- 个人组：独舞\n- 双人组：双人舞\n- 团体组：3人以上群舞\n\n## 舞种要求\n\n民族舞、古典舞、现代舞、街舞、拉丁舞等均可参赛。\n\n## 比赛流程\n\n1. 报名阶段：5月13日-5月20日\n2. 初赛：5月25日\n3. 决赛：6月5日\n\n## 奖项设置\n\n各组别设一、二、三等奖及最佳创意奖、最佳表演奖。\n\n## 报名方式\n\n请填写报名表发送至dance@university.edu.cn\n\n联系人：李同学 13912345678\n\n期待在舞台上看到你的精彩表现！', NULL, '2016200001000000002', '李思雨', 145, 0, 0, 0, 0, 1, '2026-05-13 10:30:00', '2016200001000000002', '2026-05-13 10:30:00', '', '2026-05-13 10:30:00', 0),

('2016300001002000005', '212', '相声小品大赛精彩回顾', '欢声笑语，乐动校园', '# 相声小品大赛回顾\n\n5月14日晚，校园相声小品大赛在大学生活动中心成功举办。\n\n## 获奖名单\n\n### 相声组\n- 一等奖：《大学生活》- 计算机学院\n- 二等奖：《我的室友》- 外国语学院\n- 三等奖：《考试之后》- 经济学院\n\n### 小品组\n- 一等奖：《青春不散场》- 艺术学院\n- 二等奖：《宿舍故事》- 理学院\n- 三等奖：《面试奇遇》- 管理学院\n\n## 精彩瞬间\n\n参赛作品题材丰富，有校园生活的趣事，有对社会现象的思考，还有对青春的感悟。演员们幽默风趣的表演，让现场笑声不断。\n\n感谢所有参赛选手和幕后工作人员的付出！', NULL, '2016200001000000004', '陈晓婷', 198, 0, 0, 0, 0, 1, '2026-05-15 10:00:00', '2016200001000000004', '2026-05-15 10:00:00', '', '2026-05-15 10:00:00', 0),

('2016300001002000006', '212', '交响乐团春季音乐会预告', '古典与现代的完美融合', '# 交响乐团春季音乐会\n\n校交响乐团将于5月22日举办春季音乐会。\n\n## 演出信息\n\n- 时间：2026年5月22日 19:00\n- 地点：音乐厅\n- 指挥：音乐学院张教授\n\n## 曲目预告\n\n### 上半场：古典经典\n1. 贝多芬《第五交响曲》第一乐章\n2. 莫扎特《第40交响曲》\n3. 德沃夏克《新世界交响曲》选段\n\n### 下半场：影视金曲\n1. 《星球大战》主题曲\n2. 《泰坦尼克号》主题曲\n3. 《千与千寻》配乐\n\n## 索票方式\n\n请于5月20日前到学生服务中心领取门票，每人限领2张。\n\n欢迎喜爱古典音乐的师生前来欣赏！', NULL, '2016200001000000006', '赵雅琪', 167, 0, 0, 0, 0, 1, '2026-05-18 11:00:00', '2016200001000000006', '2026-05-18 11:00:00', '', '2026-05-18 11:00:00', 0),

('2016300001002000007', '212', '校园十佳歌手风采展示', '用歌声点亮青春', '# 十佳歌手风采\n\n2026年校园十佳歌手评选结果揭晓！让我们一睹他们的风采。\n\n## 十佳名单\n\n1. **张小明** - 计算机学院 - 擅长流行、R&B\n2. **李雨萱** - 艺术学院 - 擅长民谣\n3. **王浩天** - 外国语学院 - 擅长摇滚\n4. **陈思琪** - 经济学院 - 擅长抒情\n5. **刘子涵** - 理学院 - 擅长古风\n6. **赵雅婷** - 管理学院 - 擅长爵士\n7. **孙伟杰** - 工学院 - 擅长说唱\n8. **周雨欣** - 文学院 - 擅长流行\n9. **吴俊杰** - 法学院 - 擅长民谣\n10. **郑欣怡** - 教育学院 - 擅长流行\n\n## 获奖感言\n\n"感谢学校提供这个平台，让我能够展示自己。音乐是我生命中不可或缺的一部分。" —— 张小明\n\n恭喜所有获奖选手！', NULL, '2016200001000000007', '孙伟杰', 289, 0, 0, 0, 1, 1, '2026-05-19 15:30:00', '2016200001000000007', '2026-05-19 15:30:00', '', '2026-05-19 15:30:00', 0),

('2016300001002000008', '212', '戏曲进校园活动成功举办', '传承国粹，感受经典', '# 戏曲进校园\n\n5月17日下午，"戏曲进校园"活动在我校成功举办。省京剧团的艺术家们为师生带来了一场精彩的戏曲盛宴。\n\n## 演出内容\n\n- 京剧《贵妃醉酒》选段\n- 京剧《霸王别姬》选段\n- 豫剧《花木兰》选段\n- 越剧《梁山伯与祝英台》选段\n\n## 互动环节\n\n艺术家们还现场教授了戏曲身段和唱腔，同学们踊跃参与，气氛热烈。\n\n## 学生感言\n\n"以前觉得戏曲离我们很远，今天看了演出才发现戏曲这么有魅力。"\n"艺术家们的表演太精彩了，让我对传统文化有了新的认识。"\n\n本次活动让同学们近距离感受了传统戏曲的魅力，增强了文化自信。', NULL, '2016200001000000009', '吴俊杰', 134, 0, 0, 0, 0, 1, '2026-05-17 18:00:00', '2016200001000000009', '2026-05-17 18:00:00', '', '2026-05-17 18:00:00', 0),

('2016300001002000009', '212', '校园音乐节即将开幕', '音乐狂欢，激情夏日', '# 校园音乐节\n\n一年一度的校园音乐节将于5月25日盛大开幕！\n\n## 活动安排\n\n### 5月25日\n- 14:00-18:00 校园乐队展演\n- 19:00-21:30 晚会演出\n\n### 5月26日\n- 10:00-12:00 音乐工作坊\n- 14:00-18:00 DJ表演\n- 19:00-21:30 闭幕演出\n\n## 演出阵容\n\n- 校园十大乐队\n- 特邀嘉宾：知名独立音乐人\n- DJ表演\n\n## 活动地点\n\n大学生活动中心广场\n\n## 参与方式\n\n免费入场，欢迎所有师生参加！\n\n让我们一起在音乐中释放青春！', NULL, '2016200001000000008', '周雨萱', 356, 0, 0, 0, 1, 1, '2026-05-20 10:00:00', '2016200001000000008', '2026-05-20 10:00:00', '', '2026-05-20 10:00:00', 0),

('2016300001002000010', '212', '合唱团参加省级比赛获金奖', '歌声嘹亮，载誉而归', '# 合唱团喜获金奖\n\n在刚刚结束的全省大学生合唱比赛中，我校合唱团凭借出色的表现荣获金奖！\n\n## 比赛回顾\n\n本次比赛共有来自全省30余所高校的合唱团参赛。我校合唱团演唱了《黄河大合唱》和《在希望的田野上》两首曲目，以饱满的情感和精湛的技巧征服了评委和观众。\n\n## 团员感言\n\n"为了这次比赛，我们准备了整整半年。每天排练3个小时，虽然辛苦但很值得！" —— 合唱团团长\n\n"这次获奖是对我们努力的最好回报，感谢学校和老师们的支持！"\n\n## 未来计划\n\n合唱团将继续努力，争取在全国比赛中取得好成绩。同时，也欢迎热爱歌唱的同学加入！', NULL, '2016200001000000010', '郑欣怡', 245, 0, 0, 0, 1, 1, '2026-05-18 20:00:00', '2016200001000000010', '2026-05-18 20:00:00', '', '2026-05-18 20:00:00', 0),

-- ==================== 志愿服务 (213) 10篇 ====================
('2016300001003000001', '213', '志愿服务 | 关爱留守儿童公益活动招募志愿者', '用爱点亮希望', '# 公益活动招募\n\n为关爱农村留守儿童，校青年志愿者协会将组织为期一天的公益活动。\n\n## 活动详情\n\n- 时间：2026年5月22日 8:00-17:00\n- 地点：阳光小学（距学校约30公里）\n- 内容：课业辅导、趣味游戏、爱心捐赠\n\n## 志愿者要求\n\n1. 有爱心、有耐心\n2. 能够全程参与活动\n3. 有支教经验者优先\n\n## 活动流程\n\n- 8:00 学校集合出发\n- 9:30 到达阳光小学\n- 10:00-12:00 课业辅导\n- 12:00-13:30 午餐休息\n- 14:00-16:00 趣味游戏\n- 16:00-16:30 爱心捐赠\n- 17:00 返程\n\n## 报名方式\n\n请于5月19日前联系志愿者协会报名。\n\n让我们一起传递温暖！', NULL, '2016200001000000002', '李思雨', 67, 0, 0, 0, 0, 1, '2026-05-17 11:45:00', '2016200001000000002', '2026-05-17 11:45:00', '', '2026-05-17 11:45:00', 0),

('2016300001003000002', '213', '无偿献血活动圆满结束', '热血青春，爱心传递', '# 无偿献血活动回顾\n\n5月16日，我校联合市中心血站举办了无偿献血活动，共有328名师生参与献血，献血总量达65600毫升。\n\n## 活动现场\n\n早上8点，献血车前就排起了长队。同学们在志愿者的引导下，有序进行登记、体检、献血。\n\n## 感人瞬间\n\n- 大三学生张同学已经是第4次献血，他说："献血是力所能及的善事，我会坚持下去。"\n- 来自医学院的李同学说："作为医学生，我更懂得血液对病人的重要。"\n\n## 感谢\n\n感谢所有参与献血的师生，你们的热血将挽救更多生命！感谢志愿者的辛勤付出！', NULL, '2016200001000000001', '张明华', 189, 0, 0, 0, 0, 1, '2026-05-17 09:00:00', '2016200001000000001', '2026-05-17 09:00:00', '', '2026-05-17 09:00:00', 0),

('2016300001003000003', '213', '环保志愿活动 | 清洁校园，美化环境', '共建美丽校园', '# 清洁校园活动\n\n为营造整洁优美的校园环境，志愿者协会组织了"清洁校园，美化环境"活动。\n\n## 活动信息\n\n- 时间：2026年5月18日 14:00-17:00\n- 集合地点：图书馆广场\n- 活动范围：教学楼周边、宿舍区、操场\n\n## 活动内容\n\n1. 清理校园垃圾\n2. 整理自行车停放区\n3. 清除小广告\n4. 绿化带除草\n\n## 注意事项\n\n- 请穿着方便活动的服装\n- 协会将提供手套、垃圾袋等工具\n- 活动结束后可获得志愿服务时长认证\n\n## 报名方式\n\n扫描二维码加入活动群\n\n让我们一起行动，让校园更美丽！', NULL, '2016200001000000003', '王浩然', 78, 0, 0, 0, 0, 1, '2026-05-16 15:00:00', '2016200001000000003', '2026-05-16 15:00:00', '', '2026-05-16 15:00:00', 0),

('2016300001003000004', '213', '敬老院慰问活动招募志愿者', '关爱老人，传递温暖', '# 敬老院慰问活动\n\n校志愿者协会将组织敬老院慰问活动，为老人们送去温暖和欢乐。\n\n## 活动安排\n\n- 时间：2026年5月21日 9:00-12:00\n- 地点：阳光敬老院\n- 人数：限20人\n\n## 活动内容\n\n1. 与老人聊天谈心\n2. 表演文艺节目\n3. 帮助打扫卫生\n4. 赠送慰问品\n\n## 志愿者要求\n\n- 有爱心、有耐心\n- 善于与老人沟通\n- 有才艺者优先（唱歌、跳舞、书法等）\n\n## 报名方式\n\n请联系活动负责人：王同学 13812345678\n\n名额有限，先到先得！', NULL, '2016200001000000005', '刘子轩', 56, 0, 0, 0, 0, 1, '2026-05-18 10:00:00', '2016200001000000005', '2026-05-18 10:00:00', '', '2026-05-18 10:00:00', 0),

('2016300001003000005', '213', '图书馆志愿服务活动开始招募', '书香伴我行', '# 图书馆志愿者招募\n\n图书馆现招募志愿者协助日常管理工作。\n\n## 服务内容\n\n1. 图书整理上架\n2. 协助读者借还书\n3. 维持阅览室秩序\n4. 协助举办阅读活动\n\n## 服务时间\n\n- 每周一至周五\n- 上午：9:00-12:00\n- 下午：14:00-17:00\n- 每次服务不少于2小时\n\n## 志愿者福利\n\n1. 志愿服务时长认证\n2. 优先参与图书馆活动\n3. 年度优秀志愿者表彰\n4. 免费借阅名额增加\n\n## 报名条件\n\n1. 热爱阅读，有责任心\n2. 每周至少服务4小时\n3. 服务期限不少于一个学期\n\n报名地点：图书馆一楼服务台', NULL, '2016200001000000004', '陈晓婷', 89, 0, 0, 0, 0, 1, '2026-05-15 14:30:00', '2016200001000000004', '2026-05-15 14:30:00', '', '2026-05-15 14:30:00', 0),

('2016300001003000006', '213', '爱心义卖活动成功举办', '小善大爱，温暖人心', '# 爱心义卖活动回顾\n\n5月19日，志愿者协会举办的爱心义卖活动圆满结束，共筹得善款8560元。\n\n## 活动现场\n\n活动现场热闹非凡，同学们纷纷拿出闲置物品进行义卖。书籍、文具、手工艺品、自制美食......琳琅满目。\n\n## 精彩瞬间\n\n- 手工社团制作的精美饰品深受欢迎\n- 美食区的自制蛋糕很快售罄\n- 许多同学主动捐款\n\n## 善款用途\n\n本次义卖所得善款将全部用于资助贫困山区学生，为他们购买学习用品和生活物资。\n\n## 感谢\n\n感谢所有参与义卖和购买的师生，感谢志愿者的辛勤付出！', NULL, '2016200001000000006', '赵雅琪', 134, 0, 0, 0, 0, 1, '2026-05-20 09:00:00', '2016200001000000006', '2026-05-20 09:00:00', '', '2026-05-20 09:00:00', 0),

('2016300001003000007', '213', '义务支教活动报名开始', '用知识点亮未来', '# 义务支教招募\n\n志愿者协会将组织暑期义务支教活动，前往偏远山区小学支教。\n\n## 活动信息\n\n- 时间：2026年7月10日-7月25日\n- 地点：云南省某山区小学\n- 人数：15人\n\n## 支教内容\n\n1. 语文、数学、英语基础课程\n2. 音乐、美术、体育等兴趣课程\n3. 心理健康教育\n4. 安全知识讲座\n\n## 报名条件\n\n1. 身体健康，能适应山区生活\n2. 有教学热情，有耐心\n3. 有特长者优先\n4. 能全程参与\n\n## 福利保障\n\n- 往返交通费报销\n- 提供食宿\n- 志愿服务时长认证\n- 社会实践证明\n\n报名截止：5月30日', NULL, '2016200001000000007', '孙伟杰', 167, 0, 0, 0, 0, 1, '2026-05-19 11:00:00', '2016200001000000007', '2026-05-19 11:00:00', '', '2026-05-19 11:00:00', 0),

('2016300001003000008', '213', '文明交通志愿服务活动', '守护安全，文明出行', '# 文明交通志愿服务\n\n为倡导文明出行，志愿者协会将组织文明交通志愿服务活动。\n\n## 活动安排\n\n- 时间：每周六、周日 8:00-11:00\n- 地点：学校周边主要路口\n- 内容：协助交警维持交通秩序\n\n## 服务内容\n\n1. 引导行人遵守交通规则\n2. 协助老人、儿童过马路\n3. 宣传交通安全知识\n4. 劝导不文明交通行为\n\n## 志愿者要求\n\n1. 身体健康\n2. 有责任心\n3. 服从安排\n\n## 报名方式\n\n请加入志愿者QQ群：123456789\n\n让我们一起守护交通安全！', NULL, '2016200001000000009', '吴俊杰', 45, 0, 0, 0, 0, 1, '2026-05-14 16:00:00', '2016200001000000009', '2026-05-14 16:00:00', '', '2026-05-14 16:00:00', 0),

('2016300001003000009', '213', '植树节志愿活动回顾', '种下希望，收获绿色', '# 植树活动回顾\n\n5月13日，志愿者协会组织了植树活动，共有50名志愿者参与，种植树苗200余棵。\n\n## 活动现场\n\n早上8点，志愿者们带着工具来到植树地点。大家分工合作，挖坑、栽树、浇水，干劲十足。\n\n## 活动成果\n\n经过3个小时的努力，200余棵树苗在校园北区的荒地上扎根。这些树苗包括银杏、桂花、香樟等品种。\n\n## 志愿者感言\n\n"虽然很累，但看到自己亲手种下的树苗，很有成就感。"\n"希望这些小树苗能茁壮成长，为校园增添一抹绿色。"\n\n## 后续安排\n\n志愿者协会将定期组织浇水、除草活动，确保树苗成活。', NULL, '2016200001000000008', '周雨萱', 98, 0, 0, 0, 0, 1, '2026-05-14 10:00:00', '2016200001000000008', '2026-05-14 10:00:00', '', '2026-05-14 10:00:00', 0),

('2016300001003000010', '213', '社区服务志愿活动招募', '走进社区，服务群众', '# 社区服务活动\n\n志愿者协会将组织社区服务活动，为社区居民提供便民服务。\n\n## 活动信息\n\n- 时间：2026年5月24日 9:00-12:00\n- 地点：阳光社区\n- 内容：便民服务、政策宣传\n\n## 服务项目\n\n1. 义务维修：小家电维修\n2. 健康咨询：量血压、健康指导\n3. 法律咨询：法律知识普及\n4. 手机教学：教老人使用智能手机\n5. 环保宣传：垃圾分类知识\n\n## 志愿者要求\n\n1. 有相关技能或知识\n2. 热情耐心\n3. 善于沟通\n\n## 报名方式\n\n请联系活动负责人报名\n\n让我们用实际行动服务社区！', NULL, '2016200001000000010', '郑欣怡', 67, 0, 0, 0, 0, 1, '2026-05-20 14:00:00', '2016200001000000010', '2026-05-20 14:00:00', '', '2026-05-20 14:00:00', 0),

-- ==================== 心理咨询 (231) 10篇 ====================
('2016300001004000001', '231', '心理咨询中心开放预约', '你的心事，我们倾听', '# 心理咨询预约\n\n亲爱的同学们：\n\n学业压力、人际关系、情感困惑......如果你有任何心理困扰，心理咨询中心随时为你提供帮助。\n\n## 预约方式\n\n- 线上预约：校园智通平台-心理咨询模块\n- 电话预约：0123-8888888\n- 现场预约：学生服务中心302室\n\n## 服务时间\n\n周一至周五 9:00-17:00\n\n## 咨询内容\n\n1. 学业压力\n2. 人际关系\n3. 情感问题\n4. 情绪管理\n5. 职业规划\n6. 其他心理困扰\n\n## 保密承诺\n\n所有咨询内容严格保密，请放心预约。\n\n我们在这里等你。', NULL, '2016200001000000007', '孙伟杰', 45, 0, 0, 0, 0, 1, '2026-05-18 16:30:00', '2016200001000000007', '2026-05-18 16:30:00', '', '2026-05-18 16:30:00', 0),

('2016300001004000002', '231', '如何应对考试焦虑', '轻松应考，从容面对', '# 考试焦虑应对指南\n\n期末考试临近，你是否感到焦虑不安？以下是一些应对考试焦虑的方法：\n\n## 认识考试焦虑\n\n考试焦虑是一种常见的心理状态，适度的焦虑可以提高学习效率，但过度焦虑会影响发挥。\n\n## 应对方法\n\n### 1. 充分准备\n- 制定合理的复习计划\n- 分解学习任务\n- 及时复习巩固\n\n### 2. 调整心态\n- 接纳焦虑情绪\n- 积极自我暗示\n- 关注过程而非结果\n\n### 3. 放松技巧\n- 深呼吸练习\n- 渐进式肌肉放松\n- 冥想练习\n\n### 4. 规律作息\n- 保证充足睡眠\n- 适当运动\n- 健康饮食\n\n## 寻求帮助\n\n如果焦虑严重影响学习和生活，请及时预约心理咨询。', NULL, '2016200001000000001', '张明华', 89, 0, 0, 0, 0, 1, '2026-05-15 10:00:00', '2016200001000000001', '2026-05-15 10:00:00', '', '2026-05-15 10:00:00', 0),

('2016300001004000003', '231', '人际交往中的心理技巧', '建立良好人际关系', '# 人际交往技巧\n\n良好的人际关系是大学生活的重要组成部分。以下是一些实用的交往技巧：\n\n## 沟通技巧\n\n### 1. 学会倾听\n- 保持眼神交流\n- 不打断对方\n- 适时回应\n\n### 2. 表达清晰\n- 说出自己的想法\n- 使用"我"的陈述\n- 避免指责\n\n### 3. 换位思考\n- 站在对方角度\n- 理解他人感受\n- 尊重差异\n\n## 处理冲突\n\n- 冷静面对\n- 寻找共同点\n- 寻求妥协\n- 必要时寻求帮助\n\n## 建立友谊\n\n- 真诚待人\n- 主动交往\n- 保持联系\n- 互相支持', NULL, '2016200001000000003', '王浩然', 123, 0, 0, 0, 0, 1, '2026-05-16 14:00:00', '2016200001000000003', '2026-05-16 14:00:00', '', '2026-05-16 14:00:00', 0),

('2016300001004000004', '231', '如何管理负面情绪', '做情绪的主人', '# 情绪管理指南\n\n每个人都会经历负面情绪，关键是如何有效管理它们。\n\n## 常见负面情绪\n\n- 焦虑\n- 愤怒\n- 悲伤\n- 失落\n- 嫉妒\n\n## 管理方法\n\n### 1. 觉察情绪\n- 识别自己的情绪\n- 了解情绪来源\n- 接纳情绪存在\n\n### 2. 表达情绪\n- 找人倾诉\n- 写日记\n- 运动释放\n\n### 3. 调节情绪\n- 深呼吸\n- 正念冥想\n- 转移注意力\n\n### 4. 解决问题\n- 分析原因\n- 制定方案\n- 采取行动\n\n## 专业帮助\n\n如果情绪问题持续困扰你，请预约心理咨询。', NULL, '2016200001000000005', '刘子轩', 156, 0, 0, 0, 0, 1, '2026-05-17 11:00:00', '2016200001000000005', '2026-05-17 11:00:00', '', '2026-05-17 11:00:00', 0),

('2016300001004000005', '231', '大学生心理健康自测', '了解自己的心理状态', '# 心理健康自测\n\n想知道自己的心理状态如何？来做一个小测试吧！\n\n## 睡眠质量\n\n1. 入睡困难吗？\n2. 经常做梦吗？\n3. 早醒后难以入睡吗？\n4. 白天感到疲惫吗？\n\n## 情绪状态\n\n1. 经常感到焦虑吗？\n2. 容易发脾气吗？\n3. 对未来感到迷茫吗？\n4. 对事物失去兴趣吗？\n\n## 人际关系\n\n1. 与同学相处融洽吗？\n2. 有可以倾诉的朋友吗？\n3. 感到孤独吗？\n\n## 学习状态\n\n1. 能集中注意力学习吗？\n2. 对学习有动力吗？\n3. 学习效率如何？\n\n## 提示\n\n如果多个问题答案让你担忧，建议预约心理咨询进行专业评估。', NULL, '2016200001000000002', '李思雨', 234, 0, 0, 0, 0, 1, '2026-05-18 09:00:00', '2016200001000000002', '2026-05-18 09:00:00', '', '2026-05-18 09:00:00', 0),

('2016300001004000006', '231', '如何克服社交恐惧', '勇敢迈出第一步', '# 克服社交恐惧\n\n社交恐惧是很多同学面临的问题，以下是一些克服方法：\n\n## 认识社交恐惧\n\n社交恐惧表现为在社交场合感到紧张、害怕被评价、回避社交活动等。\n\n## 克服方法\n\n### 1. 渐进暴露\n- 从小范围社交开始\n- 逐步扩大社交圈\n- 设定小目标\n\n### 2. 认知重构\n- 挑战负面想法\n- 建立积极认知\n- 接受不完美\n\n### 3. 技能训练\n- 练习社交技巧\n- 准备话题\n- 观察他人\n\n### 4. 放松练习\n- 深呼吸\n- 渐进式放松\n\n## 寻求支持\n\n- 加入兴趣社团\n- 找朋友陪伴\n- 必要时寻求专业帮助', NULL, '2016200001000000004', '陈晓婷', 178, 0, 0, 0, 0, 1, '2026-05-19 15:00:00', '2016200001000000004', '2026-05-19 15:00:00', '', '2026-05-19 15:00:00', 0),

('2016300001004000007', '231', '失恋后如何调整心态', '走出情感阴霾', '# 失恋心理调适\n\n失恋是人生中可能经历的情感挫折，以下是一些调适方法：\n\n## 允许自己悲伤\n\n失恋后感到难过是正常的，不要压抑自己的情绪。\n\n## 调适方法\n\n### 1. 接受现实\n- 承认关系结束\n- 不要自责\n- 给自己时间\n\n### 2. 表达情感\n- 哭泣释放\n- 找人倾诉\n- 写日记\n\n### 3. 转移注意力\n- 投入学习\n- 培养爱好\n- 结交新朋友\n\n### 4. 自我成长\n- 反思学习\n- 提升自己\n- 规划未来\n\n## 何时寻求帮助\n\n- 持续抑郁超过两周\n- 影响正常生活\n- 有自伤想法', NULL, '2016200001000000006', '赵雅琪', 145, 0, 0, 0, 0, 1, '2026-05-20 10:00:00', '2016200001000000006', '2026-05-20 10:00:00', '', '2026-05-20 10:00:00', 0),

('2016300001004000008', '231', '如何建立自信心', '相信自己，勇敢前行', '# 建立自信心\n\n自信是成功的重要因素，以下是一些建立自信的方法：\n\n## 认识自己\n\n- 了解自己的优点\n- 接纳自己的不足\n- 发现自己的潜力\n\n## 建立方法\n\n### 1. 设定小目标\n- 制定可实现的目标\n- 逐步挑战更大目标\n- 记录成功经历\n\n### 2. 积极自我对话\n- 用积极语言鼓励自己\n- 停止自我否定\n- 肯定自己的努力\n\n### 3. 提升能力\n- 学习新技能\n- 持续进步\n- 获得成就感\n\n### 4. 改变形象\n- 注意仪表\n- 保持微笑\n- 良好姿态\n\n## 实践建议\n\n- 每天记录三件成功的事\n- 勇敢尝试新事物\n- 与积极的人交往', NULL, '2016200001000000009', '吴俊杰', 167, 0, 0, 0, 0, 1, '2026-05-13 15:00:00', '2016200001000000009', '2026-05-13 15:00:00', '', '2026-05-13 15:00:00', 0),

('2016300001004000009', '231', '学业压力应对指南', '平衡学习与生活', '# 学业压力应对\n\n大学生面临各种学业压力，以下是一些应对方法：\n\n## 压力来源\n\n- 课程难度\n- 考试压力\n- 竞争压力\n- 就业压力\n\n## 应对策略\n\n### 1. 时间管理\n- 制定学习计划\n- 合理分配时间\n- 避免拖延\n\n### 2. 学习方法\n- 找到适合自己的方法\n- 主动学习\n- 寻求帮助\n\n### 3. 压力释放\n- 适当运动\n- 培养爱好\n- 与朋友交流\n\n### 4. 保持平衡\n- 规律作息\n- 健康饮食\n- 适度娱乐\n\n## 寻求支持\n\n- 向老师请教\n- 与同学讨论\n- 预约学业指导\n- 心理咨询', NULL, '2016200001000000008', '周雨萱', 198, 0, 0, 0, 0, 1, '2026-05-14 11:00:00', '2016200001000000008', '2026-05-14 11:00:00', '', '2026-05-14 11:00:00', 0),

('2016300001004000010', '231', '心理咨询常见问题解答', '关于咨询你想知道的', '# 心理咨询FAQ\n\n## Q1：什么情况需要心理咨询？\n\n- 情绪困扰影响生活\n- 人际关系问题\n- 学业压力过大\n- 情感问题\n- 自我探索需求\n\n## Q2：心理咨询会保密吗？\n\n是的，所有咨询内容严格保密。但在涉及自伤、伤人等特殊情况时，咨询师有责任采取必要措施。\n\n## Q3：心理咨询需要多长时间？\n\n每次咨询约50分钟，一般需要4-10次，具体根据个人情况而定。\n\n## Q4：咨询师会给我建议吗？\n\n咨询师不会直接给建议，而是帮助你探索问题，找到适合自己的解决方案。\n\n## Q5：预约后可以取消吗？\n\n可以，请提前24小时取消，以便其他同学预约。\n\n## 预约方式\n\n- 校园智通平台\n- 电话：0123-8888888\n- 现场：学生服务中心302室', NULL, '2016200001000000010', '郑欣怡', 89, 0, 0, 0, 0, 1, '2026-05-15 16:00:00', '2016200001000000010', '2026-05-15 16:00:00', '', '2026-05-15 16:00:00', 0),

