('2016300001008000001', '711', '校篮球联赛 | 计算机学院晋级四强', '精彩比赛回顾', '# 篮球联赛战报\n\n在5月15日进行的校篮球联赛四分之一决赛中，计算机学院以68:52战胜经济学院，成功晋级四强。\n\n## 比赛亮点\n\n### 第一节\n计算机学院以18:12领先，队长张明华独得8分。\n\n### 第二节\n经济学院加强防守，半场结束计算机学院以32:28领先。\n\n### 第三节\n计算机学院打出进攻高潮，单节得到22分。\n### 第四节\n经济学院奋力追赶，但分差过大，最终计算机学院获胜。\n\n## 数据统计\n\n- 张明华：25分、8篮板、5助攻\n- 李强：15分、10篮板\n- 王伟：12分、6助攻\n\n## 下一场对手\n\n半决赛将对阵机械学院，时间：5月20日 16:00。\n\n欢迎同学们到场加油！', NULL, '2016200001000000008', '周雨萱', 321, 0, 0, 0, 1, 1, '2026-05-15 21:00:00', '2016200001000000008', '2026-05-15 21:00:00', '', '2026-05-15 21:00:00', 0),

('2016300001008000002', '711', '校足球联赛决赛预告', '巅峰对决，谁与争锋', '# 足球联赛决赛\n\n2026年校足球联赛决赛即将打响！\n\n## 比赛信息\n\n- 时间：5月22日 16:00\n- 地点：田径场\n- 对阵：管理学院 VS 外国语学院\n\n## 两队战绩\n\n### 管理学院\n- 小组赛：4胜1平\n- 半决赛：2:1战胜工学院\n- 特点：进攻犀利，场均进球2.5个\n\n### 外国语学院\n- 小组赛：3胜2平\n- 半决赛：1:0战胜理学院\n- 特点：防守稳固，仅失3球\n\n## 精彩看点\n\n- 矛与盾的对决\n- 管理学院能否延续进攻火力？\n- 外国语学院能否守住防线？\n\n欢迎全校师生到场观看！', NULL, '2016200001000000001', '张明华', 267, 0, 0, 0, 0, 1, '2026-05-20 10:00:00', '2016200001000000001', '2026-05-20 10:00:00', '', '2026-05-20 10:00:00', 0),

('2016300001008000003', '711', '校运会精彩回顾', '青春飞扬，激情赛场', '# 校运会回顾\n\n5月13日-15日，2026年校运会成功举办。\n## 精彩瞬间\n\n### 田径项目\n- 100米冠军：张同学（10.8秒）\n- 400米冠军：李同学（48.5秒）\n- 跳高冠军：王同学（1.95米）\n- 跳远冠军：刘同学（7.2米）\n\n### 团体项目\n- 4×100接力：计算机学院\n- 4×400接力：经济学院\n- 拔河比赛：工学院\n\n## 团体总分\n\n1. 计算机学院：156分\n2. 经济学院：142分\n3. 工学院：128分\n\n## 破纪录情况\n\n本次校运会共打破3项校纪录：\n- 男子400米\n- 女子跳远\n- 男子铅球\n\n感谢所有参赛选手和工作人员！', NULL, '2016200001000000003', '王浩然', 345, 0, 0, 0, 1, 1, '2026-05-16 09:00:00', '2016200001000000003', '2026-05-16 09:00:00', '', '2026-05-16 09:00:00', 0),

('2016300001008000004', '711', '乒乓球联赛火热进行中', '国球风采，精彩对决', '# 乒乓球联赛\n\n校乒乓球联赛正在火热进行中！\n\n## 赛程安排\n\n### 小组赛（5月13日-17日）\n- 男子单打\n- 女子单打\n- 混合双打\n\n### 淘汰赛（5月18日-20日）\n- 四分之一决赛\n- 半决赛\n- 决赛\n\n## 目前战况\n\n### 男子单打\n- 晋级八强：张明、李强、王伟等\n### 女子单打\n- 晋级八强：陈静、刘芳、赵敏等\n\n## 比赛地点\n\n体育馆乒乓球室\n\n欢迎同学们前来观看！', NULL, '2016200001000000005', '刘子轩', 178, 0, 0, 0, 0, 1, '2026-05-18 11:00:00', '2016200001000000005', '2026-05-18 11:00:00', '', '2026-05-18 11:00:00', 0),

('2016300001008000005', '711', '羽毛球比赛报名开始', '羽球飞扬，青春激昂', '# 羽毛球比赛\n\n校羽毛球比赛报名开始！\n\n## 比赛项目\n\n- 男子单打\n- 女子单打\n- 男子双打\n- 女子双打\n- 混合双打\n\n## 比赛时间\n\n- 报名：5月13日-20日\n- 比赛：5月25日-30日\n\n## 比赛地点\n\n体育馆羽毛球场\n\n## 报名条件\n\n- 在校学生\n- 身体健康\n- 每人限报2个项目\n\n## 奖项设置\n\n各项目设一、二、三等奖，颁发证书和奖品。\n\n## 报名方式\n\n请登录校园智通平台-体育赛事模块报名\n\n期待你的参与！', NULL, '2016200001000000002', '李思雨', 145, 0, 0, 0, 0, 1, '2026-05-14 10:00:00', '2016200001000000002', '2026-05-14 10:00:00', '', '2026-05-14 10:00:00', 0),

('2016300001008000006', '711', '网球邀请赛成功举办', '挥拍之间，尽显风采', '# 网球邀请赛\n\n5月18日，校网球邀请赛成功举办。\n\n## 比赛概况\n\n- 参赛选手：32人\n- 比赛形式：单淘汰制\n- 比赛地点：网球场\n\n## 精彩对决\n\n### 半决赛\n- 张同学 VS 李同学：6:4, 6:3\n- 王同学 VS 刘同学：7:5, 6:4\n\n### 决赛\n- 张同学 VS 王同学：6:3, 4:6, 6:2\n\n## 获奖名单\n\n- 冠军：张同学\n- 亚军：王同学\n- 季军：李同学、刘同学\n\n## 比赛亮点\n\n决赛张同学在决胜盘落后情况下逆转获胜，展现了顽强拼搏的精神。', NULL, '2016200001000000004', '陈晓婷', 156, 0, 0, 0, 0, 1, '2026-05-19 10:00:00', '2016200001000000004', '2026-05-19 10:00:00', '', '2026-05-19 10:00:00', 0),

('2016300001008000007', '711', '游泳比赛成绩公布', '劈波斩浪，泳往直前', '# 游泳比赛成绩\n\n5月17日，校游泳比赛成功举办。\n\n## 比赛项目\n\n### 男子组\n- 50米自由泳\n- 100米自由泳\n- 50米蛙泳\n- 50米仰泳\n\n### 女子组\n- 50米自由泳\n- 100米自由泳\n- 50米蛙泳\n- 50米仰泳\n\n## 成绩公告\n\n### 男子50米自由泳\n1. 张同学 25.6秒\n2. 李同学 26.2秒\n3. 王同学 26.8秒\n\n### 女子50米自由泳\n1. 陈同学 28.3秒\n2. 刘同学 29.1秒\n3. 赵同学 29.8秒\n\n恭喜所有获奖选手！', NULL, '2016200001000000006', '赵雅琪', 189, 0, 0, 0, 0, 1, '2026-05-18 15:00:00', '2016200001000000006', '2026-05-18 15:00:00', '', '2026-05-18 15:00:00', 0),

('2016300001008000008', '711', '排球联赛半决赛预告', '网前争霸，谁主沉浮', '# 排球联赛半决赛\n\n校排球联赛半决赛即将打响！\n\n## 比赛安排\n\n### 第一场\n- 时间：5月21日 14:00\n- 对阵：计算机学院 VS 经济学院\n\n### 第二场\n- 时间：5月21日 16:00\n- 对阵：外国语学院 VS 理学院\n\n## 四强球队\n\n### 计算机学院\n- 特点：进攻强势\n- 核心球员：张明（主攻手）\n\n### 经济学院\n- 特点：防守稳健\n- 核心球员：李华（二传手）\n\n### 外国语学院\n- 特点：配合默契\n- 核心球员：王芳（接应）\n\n### 理学院\n- 特点：技术全面\n- 核心球员：刘强（自由人）\n\n欢迎同学们到场观看！', NULL, '2016200001000000007', '孙伟杰', 134, 0, 0, 0, 0, 1, '2026-05-20 14:00:00', '2016200001000000007', '2026-05-20 14:00:00', '', '2026-05-20 14:00:00', 0),

('2016300001008000009', '711', '健美操大赛精彩纷呈', '舞动青春，活力四射', '# 健美操大赛\n\n5月19日，校健美操大赛成功举办。\n\n## 比赛概况\n\n- 参赛队伍：12支\n- 比赛形式：团体赛\n- 评分标准：动作完成度、艺术表现力、团队配合\n\n## 精彩表演\n\n各参赛队伍带来了精彩的健美操表演，动作整齐划一，充满青春活力。\n\n## 获奖名单\n\n- 一等奖：艺术学院\n- 二等奖：教育学院、外国语学院\n- 三等奖：管理学院、经济学院、计算机学院\n\n## 评委点评\n\n"各队伍表现都很出色，动作规范，配合默契，展现了大学生的青春风采。"\n\n感谢所有参赛队伍和评委老师！', NULL, '2016200001000000009', '吴俊杰', 234, 0, 0, 0, 0, 1, '2026-05-20 09:00:00', '2016200001000000009', '2026-05-20 09:00:00', '', '2026-05-20 09:00:00', 0),

('2016300001008000010', '711', '定向越野挑战赛报名', '探索校园，挑战自我', '# 定向越野赛\n\n校定向越野挑战赛开始报名！\n\n## 比赛信息\n\n- 时间：5月25日 9:00\n- 地点：校园内\n- 形式：团队赛（4人一组）\n\n## 比赛规则\n\n1. 根据地图寻找打卡点\n2. 按顺序完成打卡\n3. 用时最短者获胜\n\n## 比赛路线\n\n- 起点：图书馆广场\n- 打卡点：10个（分布在校园各处）\n- 终点：体育馆\n\n## 报名条件\n\n- 在校学生\n- 身体健康\n- 4人组队报名\n\n## 奖项设置\n\n- 一等奖：1队\n- 二等奖：2队\n- 三等奖：3队\n\n报名方式：校园智通平台', NULL, '2016200001000000010', '郑欣怡', 167, 0, 0, 0, 0, 1, '2026-05-19 14:00:00', '2016200001000000010', '2026-05-19 14:00:00', '', '2026-05-19 14:00:00', 0),

