('2016300001009000001', '72', '动漫社举办Cosplay专场活动', '二次元盛宴，精彩纷呈', '# Cosplay专场\n\n5月18日，动漫社在大学生活动中心举办了Cosplay专场活动。\n\n## 活动内容\n\n### Cosplay走秀\n社员们精心装扮成各种动漫角色，在舞台上展示风采。\n\n### 角色扮演\n- 《原神》系列：刻晴、甘雨、钟离\n- 《鬼灭之刃》系列：炭治郎、祢豆子\n- 《咒术回战》系列：虎杖悠仁、五条悟\n\n### 互动环节\n- 角色猜谜\n- 动漫知识问答\n- 合影留念\n\n## 活动成果\n\n- 参与人数：300余人\n- Coser人数：50余人\n- 现场气氛热烈\n\n感谢所有参与的同学，期待下次活动！', NULL, '2016200001000000002', '李思雨', 289, 0, 0, 0, 1, 1, '2026-05-19 10:00:00', '2016200001000000002', '2026-05-19 10:00:00', '', '2026-05-19 10:00:00', 0),

('2016300001009000002', '72', '摄影社外拍活动回顾', '用镜头记录美好', '# 外拍活动\n\n5月16日，摄影社组织了校园外拍活动。\n\n## 活动信息\n\n- 时间：5月16日 15:00-18:00\n- 地点：校园各景点\n- 参与人数：30人\n\n## 拍摄主题\n\n### 校园风光\n- 图书馆\n- 教学楼\n- 操场\n- 湖边\n\n### 人像摄影\n- 社员互拍\n- 创意合影\n\n## 作品展示\n\n优秀作品将在校园摄影展中展出，并在公众号发布。\n\n## 技术分享\n\n活动结束后，社长分享了人像摄影技巧：\n1. 光线运用\n2. 构图方法\n3. 后期处理\n\n欢迎更多同学加入摄影社！', NULL, '2016200001000000003', '王浩然', 156, 0, 0, 0, 0, 1, '2026-05-17 10:00:00', '2016200001000000003', '2026-05-17 10:00:00', '', '2026-05-17 10:00:00', 0),

('2016300001009000003', '72', '辩论社举办校园辩论赛', '思辨青春，论道天下', '# 校园辩论赛\n\n5月17日，辩论社举办了校园辩论赛。\n\n## 辩题\n\n"大学生应该更注重理论学习还是实践能力？"\n\n## 正方观点\n\n- 理论是实践的基础\n- 扎实的理论知识是核心竞争力\n- 理论指导实践\n\n## 反方观点\n\n- 实践出真知\n- 实践能力更受用人单位青睐\n- 理论需要实践检验\n\n## 比赛结果\n\n- 获胜方：反方\n- 最佳辩手：张同学\n\n## 评委点评\n\n"双方辩手准备充分，论点清晰，辩论精彩。"', NULL, '2016200001000000005', '刘子轩', 178, 0, 0, 0, 0, 1, '2026-05-18 09:00:00', '2016200001000000005', '2026-05-18 09:00:00', '', '2026-05-18 09:00:00', 0),

('2016300001009000004', '72', '书法社举办书法作品展', '翰墨飘香，文化传承', '# 书法作品展\n\n5月15日-20日，书法社在图书馆一楼举办书法作品展。\n\n## 展览内容\n\n### 作品类型\n- 楷书\n- 行书\n- 草书\n- 隶书\n- 篆书\n\n### 作品主题\n- 古诗词\n- 名言警句\n- 校训校风\n\n## 参展作品\n\n本次展览共展出社员作品60余幅，展现了书法艺术的魅力。\n\n## 互动活动\n\n- 现场书法体验\n- 名师指导\n- 作品义卖\n\n## 参观信息\n\n- 时间：5月15日-20日 9:00-17:00\n- 地点：图书馆一楼展厅\n- 免费参观\n\n欢迎师生前来参观！', NULL, '2016200001000000001', '张明华', 145, 0, 0, 0, 0, 1, '2026-05-16 14:00:00', '2016200001000000001', '2026-05-16 14:00:00', '', '2026-05-16 14:00:00', 0),

('2016300001009000005', '72', '街舞社举办街舞派对', '舞动青春，释放激情', '# 街舞派对\n\n5月19日晚，街舞社在大学生活动中心举办了街舞派对。\n\n## 活动内容\n\n### 舞蹈表演\n- Hip-hop表演\n- Breaking秀\n- Jazz舞蹈\n- Popping展示\n\n### 互动环节\n- 舞蹈教学\n- 自由斗舞\n- 齐舞互动\n\n## 活动亮点\n\n- 现场DJ打碟\n- 灯光效果炫酷\n- 气氛热烈\n\n## 参与人数\n\n- 表演者：30人\n- 观众：200余人\n\n## 社员感言\n\n"街舞派对太嗨了，跳了一晚上都不觉得累！"\n"希望以后多举办这样的活动。"', NULL, '2016200001000000004', '陈晓婷', 234, 0, 0, 0, 1, 1, '2026-05-20 10:00:00', '2016200001000000004', '2026-05-20 10:00:00', '', '2026-05-20 10:00:00', 0),

('2016300001009000006', '72', '文学社举办诗歌朗诵会', '诗意青春，朗诵经典', '# 诗歌朗诵会\n\n5月18日，文学社在图书馆报告厅举办了诗歌朗诵会。\n\n## 朗诵内容\n\n### 古典诗词\n- 《将进酒》- 李白\n- 《水调歌头》- 苏轼\n- 《春江花月夜》- 张若虚\n\n### 现代诗歌\n- 《再别康桥》- 徐志摩\n- 《致橡树》- 舒婷\n- 《面朝大海，春暖花开》- 海子\n\n### 原创诗歌\n- 社员原创作品朗诵\n\n## 活动亮点\n\n- 配乐朗诵\n- 情景表演\n- 观众互动\n\n## 参与人数\n\n- 朗诵者：20人\n- 观众：150余人\n\n感谢所有参与的同学！', NULL, '2016200001000000006', '赵雅琪', 167, 0, 0, 0, 0, 1, '2026-05-19 11:00:00', '2016200001000000006', '2026-05-19 11:00:00', '', '2026-05-19 11:00:00', 0),

('2016300001009000007', '72', '电竞社举办校园电竞大赛', '电竞激情，青春热血', '# 电竞大赛\n\n5月14日-18日，电竞社举办了校园电竞大赛。\n\n## 比赛项目\n\n### 英雄联盟\n- 参赛队伍：32支\n- 比赛形式：5v5淘汰赛\n\n### 王者荣耀\n- 参赛队伍：64支\n- 比赛形式：5v5淘汰赛\n\n## 比赛结果\n\n### 英雄联盟\n- 冠军：计算机学院队\n- 亚军：经济学院队\n\n### 王者荣耀\n- 冠军：外国语学院队\n- 亚军：管理学院队\n\n## 活动亮点\n\n- 专业解说\n- 现场直播\n- 精美奖品\n\n## 参与人数\n\n总参与人数超过500人，现场观众累计超过2000人次。', NULL, '2016200001000000008', '周雨萱', 456, 0, 0, 0, 1, 1, '2026-05-19 15:00:00', '2016200001000000008', '2026-05-19 15:00:00', '', '2026-05-19 15:00:00', 0),

