('2016300001012000003', '513', '创业导师面对面活动', '与成功创业者交流', '# 创业导师面对面\n\n学校将举办创业导师面对面活动，邀请成功创业者分享经验。\n\n## 活动信息\n\n- 时间：5月22日 14:00\n- 地点：创业孵化基地\n\n## 导师阵容\n\n1. 张明 - 某科技公司创始人\n2. 李华 - 某投资机构合伙人\n3. 王强 - 某电商平台CEO\n\n## 分享内容\n\n1. 创业经验分享\n2. 融资技巧\n3. 团队管理\n4. 现场答疑\n\n## 报名方式\n\n请联系创业指导中心\n\n名额有限，先到先得！', NULL, '2016200001000000005', '刘子轩', 156, 0, 0, 0, 0, 1, '2026-05-18 10:00:00', '2016200001000000005', '2026-05-18 10:00:00', '', '2026-05-18 10:00:00', 0),

('2016300001012000004', '513', '创业项目路演活动', '展示项目，吸引投资', '# 项目路演\n\n学校将举办创业项目路演活动，为创业者提供展示平台。\n\n## 活动信息\n\n- 时间：5月25日 14:00\n- 地点：会议中心\n\n## 路演项目\n\n1. 智能校园APP\n2. 二手交易平台\n3. 在线教育平台\n4. 校园外卖配送\n\n## 投资人\n\n活动邀请了5家投资机构参与，优秀项目有机会获得投资。\n\n## 参与方式\n\n- 项目展示：提前报名\n- 观众参与：免费入场\n\n欢迎对创业感兴趣的同学参加！', NULL, '2016200001000000002', '李思雨', 178, 0, 0, 0, 0, 1, '2026-05-19 11:00:00', '2016200001000000002', '2026-05-19 11:00:00', '', '2026-05-19 11:00:00', 0),

('2016300001012000005', '513', '创业孵化基地入驻申请', '免费办公场地等你来', '# 孵化基地入驻\n\n学校创业孵化基地现接受入驻申请！\n\n## 基地优势\n\n1. 免费办公场地（6-12个月）\n2. 创业导师指导\n3. 创业培训课程\n4. 资源对接服务\n\n## 申请条件\n\n1. 在校学生或毕业5年内\n2. 有成熟创业项目\n3. 团队3人以上\n4. 项目有创新性\n\n## 申请材料\n\n1. 项目计划书\n2. 团队介绍\n3. 身份证明\n\n## 申请方式\n\n请将材料发送至incubator@university.edu.cn\n\n截止日期：5月30日', NULL, '2016200001000000004', '陈晓婷', 145, 0, 0, 0, 0, 1, '2026-05-17 15:00:00', '2016200001000000004', '2026-05-17 15:00:00', '', '2026-05-17 15:00:00', 0),

('2016300001012000006', '513', '创业培训课程报名', '系统学习创业知识', '# 创业培训\n\n学校将开设创业培训课程，帮助有创业意向的同学系统学习创业知识。\n\n## 课程安排\n\n### 第一期：创业基础\n- 创业机会识别\n- 商业模式设计\n- 市场调研方法\n\n### 第二期：创业实践\n- 商业计划书撰写\n- 融资技巧\n- 团队组建\n\n### 第三期：创业管理\n- 财务管理\n- 市场营销\n- 风险控制\n\n## 培训时间\n\n每周六 9:00-12:00，共8周\n\n## 报名方式\n\n请联系创业指导中心\n\n名额有限，先到先得！', NULL, '2016200001000000006', '赵雅琪', 123, 0, 0, 0, 0, 1, '2026-05-18 14:00:00', '2016200001000000006', '2026-05-18 14:00:00', '', '2026-05-18 14:00:00', 0),

('2016300001012000007', '513', '创业经验分享会', '听学长学姐讲创业故事', '# 创业分享会\n\n学校将举办创业经验分享会，邀请创业成功的校友分享经验。\n\n## 分享嘉宾\n\n1. 张明（2015届）- 某科技公司创始人\n2. 李华（2016届）- 某电商平台联合创始人\n3. 王芳（2017届）- 某教育机构创始人\n\n## 分享内容\n\n1. 创业初心\n2. 创业历程\n3. 遇到的困难与解决\n4. 给学弟学妹的建议\n\n## 活动信息\n\n- 时间：5月23日 19:00\n- 地点：图书馆报告厅\n\n欢迎同学们参加！', NULL, '2016200001000000007', '孙伟杰', 167, 0, 0, 0, 0, 1, '2026-05-20 10:00:00', '2016200001000000007', '2026-05-20 10:00:00', '', '2026-05-20 10:00:00', 0),

('2016300001012000008', '513', '大学生创业融资指南', '如何获得创业资金', '# 融资指南\n\n创业融资是每个创业者必须面对的问题，以下是一些融资渠道和技巧。\n\n## 融资渠道\n\n### 1. 亲友融资\n- 金额较小\n- 门槛低\n- 注意签订协议\n\n### 2. 天使投资\n- 金额10-100万\n- 需要成熟项目\n- 出让部分股权\n\n### 3. 风险投资\n- 金额100万以上\n- 需要快速发展潜力\n- 专业投资机构\n\n### 4. 政府扶持\n- 创业担保贷款\n- 创业补贴\n- 无需出让股权\n\n## 融资技巧\n\n1. 准备完善的商业计划书\n2. 展示项目优势\n3. 合理估值\n4. 选择合适的投资人', NULL, '2016200001000000009', '吴俊杰', 198, 0, 0, 0, 0, 1, '2026-05-16 11:00:00', '2016200001000000009', '2026-05-16 11:00:00', '', '2026-05-16 11:00:00', 0),

('2016300001012000009', '513', '创业法律知识讲座', '规避创业法律风险', '# 法律知识讲座\n\n创业过程中会遇到各种法律问题，本次讲座将为你解答。\n\n## 讲座内容\n\n### 1. 公司注册\n- 公司类型选择\n- 注册流程\n- 所需材料\n\n### 2. 知识产权\n- 商标注册\n- 专利申请\n- 著作权保护\n\n### 3. 合同签订\n- 合同要素\n- 常见陷阱\n- 纠纷处理\n\n### 4. 劳动用工\n- 用工合同\n- 社保缴纳\n- 劳动纠纷\n\n## 讲座信息\n\n- 时间：5月24日 14:00\n- 地点：教学楼B101\n\n欢迎参加！', NULL, '2016200001000000008', '周雨萱', 145, 0, 0, 0, 0, 1, '2026-05-19 15:00:00', '2016200001000000008', '2026-05-19 15:00:00', '', '2026-05-19 15:00:00', 0),

